    "id": "reg-su",
    "title": "Regulamin Samorządu Uczniowskiego",
    "category": "Regulaminy",
    "source": "regulaminy/REG_03_Samorzad_Uczniowski.md",
    "download": "/docs/REG_03_Samorzad_Uczniowski.docx",
