    "id": "pzo-zawodowe",
    "title": "Przedmiotowe Zasady Oceniania – Przedmioty Zawodowe Teoretyczne",
    "category": "Ocenianie",
    "source": "pzo/PZO_5_zawodowe.md",
    "download": "/docs/PZO_5_zawodowe.docx",
